{
  "total_gaps": 5,
  "decision_gaps": [
    {
      "gap_id": "G1",
      "core_issue": "AI平台“建沐™”是否真正缩短了研发周期并降低了成本？其预测能力与实验结果的吻合度如何？",
      "from_bucket": "tech_barrier",
      "why_it_matters": "如果AI只是数据库查询工具而非预测引擎，则公司核心竞争力被严重高估，无法支撑其“平台型材料公司”的估值逻辑。",
      "decision_impact": {
        "positive": "如果AI确实将新原料筛选周期从数年缩短至数月，且预测准确率>80%，则技术壁垒成立，可支撑高估值。",
        "negative": "如果AI仅用于记录和辅助筛选，无量化缩短周期的证据，则技术壁垒被证伪，估值需大幅下调。"
      },
      "question_design": [
        {
          "question": "过去18个月内，建沐™AI系统实际完成了多少次新超分子组合的虚拟筛选？其中有多少个组合进入了湿实验验证？验证成功率是多少？",
          "intent": "验证AI的实际使用频率和预测准确率。",
          "question_type": "fact"
        },
        {
          "question": "如果没有建沐™AI系统，你们目前美妆业务中表现最好的3个大单品（如超分子VC、麦角硫因）的研发周期和成本会有什么不同？",
          "intent": "通过反事实对比，量化AI的边际贡献。",
          "question_type": "counterfactual"
        },
        {
          "question": "从现在到2026年底，建沐™AI系统要实现对跨行业（如食品、新能源）新原料的自主筛选和推荐，最关键的3个技术卡点是什么？目前哪个最卡？",
          "intent": "评估AI平台从美妆扩展到其他行业的可行性和时间表。",
          "question_type": "path"
        }
      ]
    },
    {
      "gap_id": "G2",
      "core_issue": "客户（如欧莱雅、宝洁）是否将杉海创新的改性原料视为核心依赖，还是仅作为短期卖点？是否有独家供应协议或长期采购合同？",
      "from_bucket": "customer_value",
      "why_it_matters": "如果客户仅将改性原料作为营销噱头，随时可能切换回传统原料或自研替代品，则公司收入不稳定，客户粘性极低。",
      "decision_impact": {
        "positive": "如果前5大客户均有2年以上框架协议或独家供应合同，且复购率>90%，则客户依赖性强，收入可预测。",
        "negative": "如果客户采购为单次或短期合同，且无续约承诺，则客户付费动机不稳固，存在收入骤降风险。"
      },
      "question_design": [
        {
          "question": "请列出2024年按销售额排名前5的客户，以及他们首次采购你们改性原料的具体时间。这些客户中，是否有任何一个在2024年内减少了采购量或中断了合作？",
          "intent": "了解核心客户的合作历史和稳定性。",
          "question_type": "fact"
        },
        {
          "question": "如果欧莱雅或华熙生物决定内部研发与你们超分子VC性能相当的改性原料，他们需要投入多少时间和成本？",
          "intent": "评估客户自研替代的难度和动机。",
          "question_type": "counterfactual"
        },
        {
          "question": "未来12个月内，你们计划与现有头部客户签署多少份独家供应或联合开发协议？目前有几份正在谈判中？",
          "intent": "评估客户关系深化和锁定程度。",
          "question_type": "path"
        }
      ]
    },
    {
      "gap_id": "G3",
      "core_issue": "食品原料订单300%增长的绝对金额是多少？是否已形成可持续的规模化收入？",
      "from_bucket": "commercialization",
      "why_it_matters": "如果食品业务仅是小额订单或一次性采购，则跨行业扩张的叙事被证伪，公司仍高度依赖美妆单一市场，增长天花板有限。",
      "decision_impact": {
        "positive": "如果食品订单2024年绝对金额超过2000万元，且前3大客户有续约意向，则跨行业扩张初步验证，可适度乐观。",
        "negative": "如果食品订单绝对金额低于500万元，或客户为一次性采购，则跨行业扩张风险极高，投资应主要聚焦美妆业务估值。"
      },
      "question_design": [
        {
          "question": "2024年食品原料业务的全年营收绝对金额是多少？前3大客户分别贡献了多少营收？",
          "intent": "量化食品业务的真实规模。",
          "question_type": "fact"
        },
        {
          "question": "如果你们没有超分子改性技术，食品客户目前使用的主要替代原料是什么？其成本和性能与你们的产品相比如何？",
          "intent": "评估食品业务的技术替代性和客户付费意愿。",
          "question_type": "counterfactual"
        },
        {
          "question": "食品原料从订单到规模化交付，最难通过的3个环节（如法规审批、生产放大、客户验证）是什么？目前哪个最卡？预计何时能突破？",
          "intent": "评估食品业务规模化路径的可行性和时间表。",
          "question_type": "path"
        }
      ]
    },
    {
      "gap_id": "G4",
      "core_issue": "在美妆领域，杉海创新的超分子改性技术是否容易被竞争对手模仿或绕过？其专利是否构成了真实的保护壁垒？",
      "from_bucket": "tech_barrier",
      "why_it_matters": "如果专利是外围专利或容易被规避，则公司的技术优势无法持久，客户可能转向更便宜的替代方案，导致价格战和利润压缩。",
      "decision_impact": {
        "positive": "如果核心专利（如超分子VC共晶）在权利要求中覆盖了关键工艺参数，且竞品无法绕过，则技术壁垒坚固。",
        "negative": "如果专利主要针对具体配方组合，且竞品通过调整比例或使用不同分子轻松规避，则技术壁垒脆弱。"
      },
      "question_design": [
        {
          "question": "请列举你们在美妆领域最核心的3项专利（公开号），并说明每一项专利在权利要求中具体保护了什么工艺参数或分子组合。过去3年内，你们是否对任何竞争对手发起过专利诉讼或发送过侵权警告函？",
          "intent": "检查专利的真实保护范围和执行力。",
          "question_type": "fact"
        },
        {
          "question": "如果一家新创公司（如“XX超分子科技”）试图开发与你们超分子VC性能相同的竞品，他们需要绕开你们多少项专利？最容易被绕开的是哪一项？",
          "intent": "评估专利壁垒的坚固程度。",
          "question_type": "counterfactual"
        },
        {
          "question": "未来2年内，你们计划在哪些技术节点上申请新专利以加强壁垒？这些新专利是否考虑了对现有专利的补充和防御？",
          "intent": "评估公司对技术壁垒的持续投入和战略规划。",
          "question_type": "path"
        }
      ]
    },
    {
      "gap_id": "G5",
      "core_issue": "跨行业扩张（新能源、医药）的商业化路径是否真实可行？是否有任何行业已产生规模化收入或明确客户验证？",
      "from_bucket": "commercialization",
      "why_it_matters": "如果新能源和医药业务仅停留在论文或中标公示阶段，则公司“全产业材料革命”的叙事严重不实，投资风险极高。",
      "decision_impact": {
        "positive": "如果新能源或医药业务中至少有一个已获得头部客户的正式采购订单（金额>100万元），则跨行业扩张有初步验证。",
        "negative": "如果所有跨行业业务均无收入，或仅有论文/中标公示，则这些业务为纯叙事，投资应仅基于美妆业务估值。"
      },
      "question_design": [
        {
          "question": "请提供新能源子公司千沐新能源2024年的营收数据，以及其前3大客户名称和合作起始时间。",
          "intent": "验证新能源业务的真实收入和客户基础。",
          "question_type": "fact"
        },
        {
          "question": "如果新能源客户不使用你们的超分子电解液，他们目前主要使用什么替代方案？其成本和性能与你们的产品相比如何？",
          "intent": "评估新能源业务的技术替代性和市场竞争力。",
          "question_type": "counterfactual"
        },
        {
          "question": "从目前的中标公示到新能源或医药业务的规模化收入，你们预计需要经历哪3个关键验证阶段？每个阶段预计耗时多久？",
          "intent": "评估跨行业扩张的路径和时间表。",
          "question_type": "path"
        }
      ]
    }
  ],
  "summary": "这轮尽调要搞清楚：AI平台是否真实缩短了研发周期、客户是否深度依赖而非尝鲜、食品业务规模化收入是否真实、专利壁垒是否坚固、以及跨行业扩张是否有任何实质性收入，从而验证公司是‘配方优化公司’还是‘平台型材料公司’，并据此决定估值和投资方向。"
}
